            if target == 0:
                return True
            if not num_str:
                return False
            for i in range(1, len(num_str) + 1):
                part = int(num_str[:i])
                if part <= target and can_partition(num_str[i:], target - part):
                    return True
            return False

        punishment_sum = 0
        for i in range(1, n + 1):
